/**
 * Utilitarios para formatacao e parsing de valores monetarios
 */

/**
 * Formata um numero como moeda brasileira
 */
export const formatCurrency = (value: number | string | null | undefined): string => {
    if (value === null || value === undefined) return "R$ 0,00";
    if (value === 0) return "R$ 0,00";

    // Converter string para numero, removendo caracteres nao numericos se necessario
    let numericValue: number;
    if (typeof value === 'string') {
        // Remover espacos e caracteres especiais, manter apenas numeros, virgula e ponto
        const cleanValue = value.replace(/[^\d,.-]/g, '').replace(',', '.');
        numericValue = parseFloat(cleanValue);
    } else {
        numericValue = value;
    }

    if (isNaN(numericValue) || numericValue === 0) return "R$ 0,00";

    return new Intl.NumberFormat('pt-BR', {
        style: 'currency',
        currency: 'BRL',
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
    }).format(numericValue);
};

/**
 * Formata valor em tempo real enquanto o usuario digita
 */
export const formatCurrencyInput = (value: string): string => {
    // Remover tudo exceto numeros
    const numbersOnly = value.replace(/[^\d]/g, "");

    if (numbersOnly === "") return "";

    // Converter para numero (centavos)
    const numericValue = parseInt(numbersOnly, 10);

    // Dividir por 100 para obter o valor em reais
    const realValue = numericValue / 100;

    // Formatar como moeda brasileira
    return new Intl.NumberFormat('pt-BR', {
        style: 'currency',
        currency: 'BRL',
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
    }).format(realValue);
};

/**
 * Converte string formatada de moeda para numero
 */
export const parseCurrencyToNumber = (value: string | null | undefined): number | null => {
    if (!value) return null;

    // 1. Manter apenas numeros e a virgula do decimal
    const cleanValue = value.replace(/[^\d,]/g, "");

    if (cleanValue === "") return null;

    // 2. Substituir virgula por ponto para parsing
    const normalizedValue = cleanValue.replace(",", ".");

    const numericValue = parseFloat(normalizedValue);

    return isNaN(numericValue) ? null : numericValue;
};

/**
 * Valida se uma string representa um valor monetario valido
 */
export const isValidCurrency = (value: string): boolean => {
    if (!value) return true; // Valores vazios sao validos (opcionais)

    const parsed = parseCurrencyToNumber(value);
    return parsed !== null && parsed >= 0;
};

/**
 * Formata valor inicial para exibicao em formularios
 */
export const formatInitialCurrencyValue = (value: number | string | null | undefined): string => {
    if (!value && value !== 0) return "";

    const numericValue = typeof value === 'string' ? parseFloat(value) : value;
    if (isNaN(numericValue)) return "";

    return formatCurrency(numericValue);
};

/**
 * Formata valores para exibicao em graficos usando abreviacoes (k, M)
 */
export function formatCurrencyShort(value: number): string {
    if (value >= 1000000) {
        return `R$ ${(value / 1000000).toFixed(1)}M`;
    }
    if (value >= 1000) {
        return `R$ ${(value / 1000).toFixed(1)}k`;
    }
    return formatCurrency(value);
}

/**
 * Formata valores numericos para eixos de graficos (sem R$)
 */
export function formatNumberShort(value: number): string {
    if (value >= 1000000) {
        return `${(value / 1000000).toFixed(1)}M`;
    }
    if (value >= 1000) {
        return `${(value / 1000).toFixed(1)}k`;
    }
    return value.toLocaleString('pt-BR');
}
